import{_ as a,c as r,o as t,ae as o}from"./chunks/framework.Ck3L_38O.js";const b=JSON.parse('{"title":"08 - B+Trees: The Best Data Structure in the World (CMU Intro to Database Systems)","description":"","frontmatter":{},"headers":[],"relativePath":"course/CMU_15-445_Fall2025/lec8.md","filePath":"course/CMU_15-445_Fall2025/lec8.md"}'),l={name:"course/CMU_15-445_Fall2025/lec8.md"};function d(n,e,i,s,h,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_08-b-trees-the-best-data-structure-in-the-world-cmu-intro-to-database-systems" tabindex="-1">08 - B+Trees: The Best Data Structure in the World (CMU Intro to Database Systems) <a class="header-anchor" href="#_08-b-trees-the-best-data-structure-in-the-world-cmu-intro-to-database-systems" aria-label="Permalink to &quot;08 - B+Trees: The Best Data Structure in the World (CMU Intro to Database Systems)&quot;">​</a></h1><h2 id="b-tree" tabindex="-1">B+Tree <a class="header-anchor" href="#b-tree" aria-label="Permalink to &quot;B+Tree&quot;">​</a></h2><p>B+树是一个自平衡有序 m-way 树(m 叉树，(m/2-1 &lt;= #keys &lt;= m-1))，可以在 log n 的时间内完成所有的数据结构操作。<br> B+树的叶子 Node 是 B+树的本质，它是一个有序链表，上层的 Node 只是为了更快的跳到这个有序链表的特定位置。</p><h3 id="b-tree-leaf-nodes" tabindex="-1">B+Tree Leaf Nodes <a class="header-anchor" href="#b-tree-leaf-nodes" aria-label="Permalink to &quot;B+Tree Leaf Nodes&quot;">​</a></h3><p>每一个叶子 Node 都有一些 Metadata ，它们会存储 Level, Slot, Prev, Next, High Key 等数据。</p><p>通常实际的数据存储的格式是将 key 排序放在一个数组中， value 放在一个数组中。通常，插入一个新的 key 时，都会进行一次快速排序，但这不是必须的。</p><h3 id="b-tree-operator" tabindex="-1">B+Tree Operator <a class="header-anchor" href="#b-tree-operator" aria-label="Permalink to &quot;B+Tree Operator&quot;">​</a></h3><p>Insert:</p><blockquote><p>当需要 insert 时，如果叶子 Node 足够大，直接插入就好；如果不够，需要向上拆分数据结构，最坏的情况可能需要重构整棵树。<br> 拆分就是将中间的 key 作为中点，一分为二，然后将中间的 key 存在上一层的 Node 中，最后向上递归拆分。</p></blockquote><p>Delete:</p><blockquote><p>delete 和 insert 基本相反。删除掉一个数据后，判断这个 Node 中的空位是否大于一半，如果不大于，那就结束了，如果大于，就会找到隔壁 Node ，看看它们的空位是否大于一半，如果大于就拿一个数据过来，更新上层 Node ，否则就合并。<br> 合并就是将两个 Node 的数据合并成一个 Node ，然后删除上一层的 Node 中的数据，最后向上递归合并。</p></blockquote><h2 id="selection-conditions" tabindex="-1">SELECTION CONDITIONS <a class="header-anchor" href="#selection-conditions" aria-label="Permalink to &quot;SELECTION CONDITIONS&quot;">​</a></h2><p>联合索引遵从最左前缀的原因是，索引建立后，是按照从左到右的顺序排序的，使用联合索引时，如果从右开始，那只能全部遍历一次。</p><h2 id="duplicate-keys" tabindex="-1">Duplicate Keys <a class="header-anchor" href="#duplicate-keys" aria-label="Permalink to &quot;Duplicate Keys&quot;">​</a></h2><p>对于重复键的解决方法通常有两个， <strong>Append Record ID</strong> 和 <strong>Overflow Leaf Nodes</strong>。</p><h3 id="append-record-id" tabindex="-1">Append Record ID <a class="header-anchor" href="#append-record-id" aria-label="Permalink to &quot;Append Record ID&quot;">​</a></h3><p>通过在复合键中添加一个隐藏的记录的唯一标识符（Record ID），确保即使原始键重复，整个复合键也是唯一的。</p><p>实现简单，逻辑清晰</p><h3 id="overflow-leaf-nodes" tabindex="-1">Overflow Leaf Nodes <a class="header-anchor" href="#overflow-leaf-nodes" aria-label="Permalink to &quot;Overflow Leaf Nodes&quot;">​</a></h3><p>允许叶 Node 在满时溢出到额外的溢出 Node ，这些溢出 Node 专门存储重复键值。</p><p>实现复杂，而且会增加树的高度，同时需要修改原本的算法，插入操作时，需要将所有涉及到溢出的溢出 Node 读取到内存中。</p><h2 id="merge-threshold" tabindex="-1">Merge Threshold <a class="header-anchor" href="#merge-threshold" aria-label="Permalink to &quot;Merge Threshold&quot;">​</a></h2><p>在传统 B+树中，合并阈值是指 Node 在删除操作后触发 Node 合并的填充率阈值 50% 。当 Node 填充率低于此阈值时，通常会触发合并操作。</p><p>在现代数据库中，例如 PostgreSQL ，把合并阈值短暂容忍为 69% ，只有当一段时间过后，或者填充率超过了 69% ，才会进行合并。</p><h2 id="variable-length-keys" tabindex="-1">Variable-length Keys <a class="header-anchor" href="#variable-length-keys" aria-label="Permalink to &quot;Variable-length Keys&quot;">​</a></h2><p>面对可变长度键，解决方法有 <strong>Pointers</strong>, <strong>Variable-length Node</strong>, <strong>Padding</strong>, <strong>Key Map / Indirection</strong> 。</p><p>Pointers:</p><blockquote><p>存键的地址</p></blockquote><p>Variable-length Node:</p><blockquote><p>使用可变长度的 Node ，实现起来困难</p></blockquote><p>Padding:</p><blockquote><p>对于不满足长度的 key ，在末尾填充 0 直至满足长度</p></blockquote><p>Key Map / Indirection:</p><blockquote><p>和 Tuple 一样，数据从末尾向开头存入，大多数数据使用它</p></blockquote><p>如果键特别大， Node 放不下，那就只能溢出了。</p><h2 id="intra-node-search" tabindex="-1">Intra-Node Search <a class="header-anchor" href="#intra-node-search" aria-label="Permalink to &quot;Intra-Node Search&quot;">​</a></h2><h3 id="linear" tabindex="-1">Linear <a class="header-anchor" href="#linear" aria-label="Permalink to &quot;Linear&quot;">​</a></h3><p>将 Node 读取到内存中，直接扫描它。</p><h3 id="binary" tabindex="-1">Binary <a class="header-anchor" href="#binary" aria-label="Permalink to &quot;Binary&quot;">​</a></h3><p>如果数据已经排序了，二分法。</p><h2 id="write-optimized-b-tree" tabindex="-1">Write-Optimized B+Tree <a class="header-anchor" href="#write-optimized-b-tree" aria-label="Permalink to &quot;Write-Optimized B+Tree&quot;">​</a></h2><p>在 MySQL 的 B+树中，非上层 Node 还会附有一个 mode log ，它类似于 Log-Structured ，每当有插入或写入进入时，直接写入 log ，当 log 满了，就放到下一层 node 的 mode log 中，直到碰到叶子 Node ，才会真正写入。</p><p>优点：减少了树的拆分和合并<br> 缺点：实现困难，当扫描时，需要注意 mode log 中的数据</p>',43)])])}const u=a(l,[["render",d]]);export{b as __pageData,u as default};
